SET NAMES utf8mb4;
ON DUPLICATE KEY UPDATE name=VALUES(name),country=VALUES(country),region=VALUES(region),tag=VALUES(tag),lat=VALUES(lat),lon=VALUES(lon),img=VALUES(img),description=VALUES(description),highlights=VALUES(highlights),food=VALUES(food),best_time=VALUES(best_time),flights=VALUES(flights),sort_order=VALUES(sort_order);
